// SPDL model for HMQV two-pass key exchange protocol
// Defines core protocol roles and cryptographic operations

// Cryptographic functions
hashfunction h1, h2, H, KDF;
function exp/2, gexp/1, add/2, mult/2;

// Helper protocols for public key setup and operations
protocol @publickeys(PK) {
    role PK {
        fresh sk: Nonce;
        var pk: Term;

        send_1(PK, PK, exp(g, sk));
        pk = exp(g, sk);
    }
}

protocol @exponentiation(RA, RB, RC) {
    role RA, RB, RC {
        send_1(RA, RB, {h1(exp(g, x))});
        send_2(RB, RC, {h2(exp(exp(g, x), y))});
        send_3(RC, RA, {H(exp(exp(exp(g, x), y), z))});
    }
}

protocol @addmult(I, R) {
    role I, R {
        send_1(I, R, {add(x, y)});
        send_2(R, I, {mult(x, y)});
    }
}

protocol @keyswap(I, R) {
    role I, R {
        fresh x, y: Nonce;
        var skI, skR: Term;

        send_1(I, R, exp(g, x));
        receive_2(R, I, Y);
        send_3(I, R, {add(x, mult(skI, H(Y)))});
        session_key = KDF(exp(Y, add(x, mult(skI, H(Y)))));
    }
}

// Main HMQV protocol definition
symmetric-protocol HMQV-twopass(I, R) {
    role I {
        fresh x: Nonce;
        var Y, SKI: Term;
        const g: Nonce;

        send_1(I, R, gexp(x));
        receive_2(R, I, Y);
        // Session key derivation (simplified representation)
        SKI = KDF(exp(Y, x), exp(Y, skI), exp(pkR, skI));
        claim(I, Secret, SKI);
        claim(I, Alive);
        claim(I, Weakagree);
    }

    role R {
        fresh y: Nonce;
        var X, SKR: Term;
        const g: Nonce;

        receive_1(I, R, X);
        send_2(R, I, gexp(y));
        // Session key derivation (symmetric computation)
        SKR = KDF(exp(X, y), exp(X, skR), exp(pkI, skR));
        claim(R, Secret, SKR);
        claim(R, Alive);
        claim(R, Nisynch);
    }
}

// Security claims for session keys
claim (I, SKI, Secret);
claim (R, SKR, Secret);
claim (I, SKI, SessionKey);
claim (R, SKR, SessionKey);
