{
    role RA
    {
        fresh x: Nonce;
        var Y, Z: Ticket;

        send_1(RA, RB, gexp(x));
        recv_3(RC, RA, Z);
    }

    role RB
    {
        fresh y: Nonce;
        var X, Z: Ticket;

        recv_1(RA, RB, X);
        send_2(RB, RC, gexp(y));
        recv_4(RC, RB, Z);
    }

    role RC
    {
        var X, Y: Ticket;
        fresh z: Nonce;

        recv_2(RB, RC, Y);
        send_3(RC, RA, exp(X, z));
        send_4(RC, RB, exp(Y, z));
    }
}

// Protocol for addition and multiplication operations
protocol @addmult(I, R)
{
    role I
    {
        fresh a, b: Nonce;
        var c, d: Nonce;

        send_1(I, R, a);
        send_2(I, R, b);
        recv_3(R, I, c);
        recv_4(R, I, d);

        claim_I1(I, Secret, add(a, c));
        claim_I2(I, Secret, mult(b, d));
    }

    role R
    {
        var a, b: Nonce;
        fresh c, d: Nonce;

        recv_1(I, R, a);
        recv_2(I, R, b);
        send_3(R, I, c);
        send_4(R, I, d);

        claim_R1(R, Secret, add(a, c));
        claim_R2(R, Secret, mult(b, d));
    }
}

// Protocol for key swapping
protocol @keyswap(I, R)
{
    role I
    {
        fresh x: Nonce;
        var Y: Ticket;

        send_1(I, R, gexp(x));
        recv_2(R, I, Y);

        claim_I(I, Secret, KDF(exp(Y, x)));
    }

    role R
    {
        var X: Ticket;
        fresh y: Nonce;

        recv_1(I, R, X);
        send_2(R, I, gexp(y));

        claim_R(R, Secret, KDF(exp(X, y)));
    }
}

// Main HMQV Two-Pass Protocol
protocol HMQV-twopass(I, R)
{
    role I
    {
        fresh x: Nonce;  // Initiator's ephemeral private key
        var Y: Ticket;   // Responder's ephemeral public key

        // I knows its own secret key sk_I and R's public key PK_R
        fresh sk_I: Ticket;
        var PK_R: Ticket;

        // Compute and send ephemeral public key
        send_1(I, R, gexp(x));

        // Receive R's ephemeral public key
        recv_2(R, I, Y);

        // Compute d = h1(X, I) and e = h2(Y, R)
        // Compute sigma = (Y * gexp(sk_R)^e)^(x + d*sk_I)
        // Derive session key
        claim_I(I, Secret, KDF(exp(mult(Y, exp(PK_R, h2(Y, R))), add(x, mult(h1(gexp(x), I), sk_I)))));

        // Authentication claim
        claim_I_auth(I, Niagree);

        // Session key secrecy
        claim_I_SKR(I, Secret, KDF(exp(mult(Y, exp(PK_R, h2(Y, R))), add(x, mult(h1(gexp(x), I), sk_I)))));
    }

    role R
    {
        var X: Ticket;   // Initiator's ephemeral public key
        fresh y: Nonce;  // Responder's ephemeral private key

        // R knows its own secret key sk_R and I's public key PK_I
        fresh sk_R: Ticket;
        var PK_I: Ticket;

        // Receive I's ephemeral public key
        recv_1(I, R, X);

