  proc dec(sk: skey, c: kct): key option
}.

(* KEM CPA adversary *)
module type KEM_CPA_Adv = {
  proc distinguish(pk: pkey, k: key, c: kct): bool
}.

(* KEM CPA experiment *)
module KEM_CPA_Exp(K: KEM, A: KEM_CPA_Adv) = {
  proc main(): bool = {
    var pk: pkey; var sk: skey;
    var k0, k1: key; var c: kct;
    var b, b': bool;

    (pk, sk) = K.keygen();
    (k0, c) = K.enc(pk);
    k1 = $dkey;
    b = ${0,1};
    b' = A.distinguish(pk, b ? k0 : k1, c);
    return (b = b');
  }
}.

(* DEM module type *)
module type DEM = {
  proc enc(k: key, m: pt): dct
  proc dec(k: key, c: dct): pt option
}.

(* DEM passive adversary *)
module type DEM_Passive_Adv = {
  proc choose(): pt * pt
  proc distinguish(c: dct): bool
}.

(* PKE module type *)
module type PKE = {
  proc keygen(): pkey * skey
  proc enc(pk: pkey, m: pt): kct * dct
  proc dec(sk: skey, c: kct * dct): pt option
}.

(* PKE CPA adversary *)
module type PKE_CPA_Adv = {
  proc choose(pk: pkey): pt * pt
  proc distinguish(c: kct * dct): bool
}.

(* KEM-DEM composition *)
module KEMDEM(K: KEM, D: DEM): PKE = {
  proc keygen(): pkey * skey = {
    return K.keygen();
  }

  proc enc(pk: pkey, m: pt): kct * dct = {
    var k: key; var c1: kct; var c2: dct;
    (k, c1) = K.enc(pk);
    c2 = D.enc(k, m);
    return (c1, c2);
  }

  proc dec(sk: skey, c: kct * dct): pt option = {
    var k_opt: key option; var m_opt: pt option;
    var c1, c2: kct * dct;
    (c1, c2) = c;
    k_opt = K.dec(sk, c1);
    if (k_opt <> None) {
      m_opt = D.dec(oget k_opt, c2);
    } else {
      m_opt = None;
    }
    return m_opt;
  }
}.

(* Security proof *)
section Proof.
  declare module K: KEM.
  declare module D: DEM.
  declare module A: PKE_CPA_Adv.

