      (m0, m1) = A.choose(pk);
      b = ${0,1};
      k = $dkey;
      (_, c1) = K.enc(pk);
      c2 = D.enc(k, b ? m0 : m1);
      b' = A.distinguish((c1, c2));
      return (b = b');
    }
  }.

  (* Reduction to KEM CPA security *)
  module B_KEM(K: KEM): KEM_CPA_Adv = {
    proc distinguish(pk: pkey, k': key, c1': kct): bool = {
      var m0, m1: pt;
      var b, b': bool;
