require import AllCore.
require import Prob.Prob.
require import Pair.
require import Option.

(* --- Type Definitions --- *)
type pkey.
type skey.
type pt.
type key.
type kct.
type dct.

(* --- Key Distribution --- *)
(* Assumed to be a uniform distribution over the key space `key`. *)
module KeyDistr = {
  proc dkey() : key
}.

(* --- KEM Specification --- *)
module type KEM_Mod_Type = {
  proc keygen() : pkey * skey
  proc enc(pk: pkey) : key * kct
  proc dec(sk: skey, c: kct) : key option
}.

(* --- CPA Adversary for KEM --- *)
(* The adversary tries to distinguish a real key from a random key.
   It outputs `false` if it thinks the key is real, `true` if it thinks it's random. *)
module type KEM_Adv_CPA_Mod_Type = {
  proc distinguish(pk: pkey, k_chal: key, c_kem: kct) : bool
}.

(* --- KEM CPA Experiment --- *)
(* The experiment provides the adversary with either a real key (k_real, c_kem)
   from KEM.enc or a random key (k_rand, c_kem).
   b_exp = false means k_chal is k_real.
   b_exp = true means k_chal is k_rand.
   The adversary wins if its output matches b_exp. *)
module KEM_CPA_Exp (KEM: KEM_Mod_Type, A: KEM_Adv_CPA_Mod_Type, KD: KeyDistr) = {
  proc main() : bool = {
    var b_exp : bool;    (* Experiment choice: false for real key, true for random key *)
    var pk    : pkey;
    var sk    : skey;
    var k_real: key;
    var k_rand: key;
    var c_kem : kct;
    var k_chal: key;
    var b_adv_guess: bool; (* Adversary's guess for b_exp *)

    b_exp <$ {0,1};
    (pk, sk) <@ KEM.keygen();
    (k_real, c_kem) <@ KEM.enc(pk);
    k_rand <@ KD.dkey();

    if (b_exp) { (* challenge with random key *)
      k_chal = k_rand;
    } else { (* challenge with real key *)
      k_chal = k_real;
    }

    b_adv_guess <@ A.distinguish(pk, k_chal, c_kem);
    return b_adv_guess = b_exp; (* Adversary wins if guess matches experiment choice *)
  }
}.

(* --- DEM Specification --- *)
module type DEM_Mod_Type = {
  proc enc(k: key, m: pt) : dct
  proc dec(k: key, c: dct) : pt (* Assumes DEM is correct and dec always returns a pt *)
}.

(* --- Passive Adversary for DEM --- *)
(* The adversary chooses two messages m0, m1.
   It receives an encryption of one of them and must guess which one. *)
module type DEM_Adv_Pass_Mod_Type = {
  proc choose() : pt * pt
  proc distinguish(c_dem_chal: dct) : bool (* Adversary's guess for the challenge bit b_exp *)
}.

(* --- DEM Passive Experiment (IND-P0-CPA) --- *)
(* The experiment encrypts m0 or m1 based on a random bit b_exp.
   The adversary wins if its output matches b_exp. *)
module DEM_Pass_Exp (DEM: DEM_Mod_Type, A: DEM_Adv_Pass_Mod_Type, KD: KeyDistr) = {
  proc main() : bool = {
    var b_exp: bool; (* Experiment choice: 0 for m0, 1 for m1 *)
    var k: key;
    var m0: pt;
    var m1: pt;
    var c_chal: dct;
    var b_adv_guess: bool; (* Adversary's guess for b_exp *)

    k <@ KD.dkey(); (* DEM key is chosen uniformly at random *)
    (m0, m1) <@ A.choose();
    b_exp <$ {0,1};

    if (b_exp) { c_chal <@ DEM.enc(k, m1); }
    else { c_chal <@ DEM.enc(k, m0); }

    b_adv_guess <@ A.distinguish(c_chal);
    return b_adv_guess = b_exp; (* Adversary wins if guess matches experiment choice *)
  }
}.

(* --- PKE Specification --- *)
module type PKE_Mod_Type = {
  proc keygen() : pkey * skey
  proc enc(pk: pkey, m: pt) : kct * dct
  proc dec(sk: skey, c: kct * dct) : pt option
}.

(* --- CPA Adversary for PKE --- *)
(* The adversary chooses two messages m0, m1 based on the public key.
   It receives an encryption of one of them and must guess which one. *)
module type PKE_Adv_CPA_Mod_Type = {
  proc choose(pk: pkey) : pt * pt
  proc distinguish(c_pke_chal: kct * dct) : bool (* Adversary's guess for the challenge bit b_exp *)
}.

(* --- PKE CPA Experiment (IND-CPA) --- *)
(* The experiment encrypts m0 or m1 based on a random bit b_exp using the PKE scheme.
   The adversary wins if its output matches b_exp. *)
module PKE_CPA_Exp (PKE: PKE_Mod_Type, A: PKE_Adv_CPA_Mod_Type) = {
  proc main() : bool = {
    var b_exp: bool; (* Experiment choice: 0 for m0, 1 for m1 *)
    var pk: pkey;
    var sk: skey;
    var m0: pt;
    var m1: pt;
    var c_chal: kct * dct;
    var b_adv_guess: bool; (* Adversary's guess for b_exp *)

    (pk, sk) <@ PKE.keygen();
    (m0, m1) <@ A.choose(pk);
    b_exp <$ {0,1};

    if (b_exp) { c_chal <@ PKE.enc(pk, m1); }
    else { c_chal <@ PKE.enc(pk, m0); }

    b_adv_guess <@ A.distinguish(c_chal);
    return b_adv_guess = b_exp; (* Adversary wins if guess matches experiment choice *)
  }
}.

(* --- KEM-DEM Composition --- *)
module KEMDEM (KEM: KEM_Mod_Type, DEM: DEM_Mod_Type) : PKE_Mod_Type = {
  proc keygen() : pkey * skey = {
    return KEM.keygen();
  }

  proc enc(pk: pkey, m: pt) : kct * dct = {
    var k_s: key;    (* Session key from KEM *)
    var c_k: kct;    (* KEM ciphertext *)
    var c_d: dct;    (* DEM ciphertext *)

    (k_s, c_k) <@ KEM.enc(pk);
    c_d <@ DEM.enc(k_s, m);
    return (c_k, c_d);
  }

  proc dec(sk: skey, c: kct * dct) : pt option = {
    var k_s_o: key option; (* Option type for KEM-decapsulated key *)
    var c_k: kct = c.`1;
    var c_d: dct = c.`2;
    var p_res: pt;

    k_s_o <@ KEM.dec(sk, c_k);
    if (k_s_o is None) {
      return None;
    } else {
      (* DEM.dec is assumed to be correct and total for valid keys & ciphertexts produced by DEM.enc *)
      p_res <@ DEM.dec(oget k_s_o, c_d);
      return Some p_res;
    }
  }
}.

(* --- Correctness Axioms --- *)
(* These would be formally stated using `call` semantics or equivalent,
   ensuring that decryption correctly inverts encryption.
   For simplicity, they are stated informally here. *)

(* KEM Correctness: For any (pk, sk) from KEM.keygen(), and (k, c_k) from KEM.enc(pk),
   KEM.dec(sk, c_k) must return Some k. *)
axiom KEM_correctness (K: KEM_Mod_Type).

(* DEM Correctness: For any key k and plaintext m,
   DEM.dec(k, DEM.enc(k, m)) must return m. *)
axiom DEM_correctness (D: DEM_Mod_Type).


(* --- Security Proof Outline: Hybrids and Reductions --- *)

(* Game G0: Original PKE_CPA_Exp with KEMDEM.
   Adv_PKE(APKE) = Pr[PKE_CPA_Exp(KEMDEM(KEM,DEM), APKE).main() @ &m: res] - 1/2.
*)

(* Game G1: PKE_CPA_Exp, but the DEM encryption uses a random key.
   This module, KEMDEM_randK, is used in an intermediate game. *)
module KEMDEM_randK (KEM: KEM_Mod_Type, DEM: DEM_Mod_Type, KD: KeyDistr) : PKE_Mod_Type = {
  proc keygen() : pkey * skey = {
    return KEM.keygen();
  }

  proc enc(pk: pkey, m: pt) : kct * dct = {
    var k_s_ignore : key; (* KEM-generated key, ignored for DEM encryption in this game *)
    var c_k        : kct; (* KEM ciphertext part, generated normally *)
    var k_eff      : key; (* Effective key for DEM, chosen randomly *)
    var c_d        : dct; (* DEM ciphertext, using k_eff *)

    (k_s_ignore, c_k) <@ KEM.enc(pk);
    k_eff <@ KD.dkey();             (* Use a fresh random key for DEM *)
    c_d <@ DEM.enc(k_eff, m);
    return (c_k, c_d);
  }

  (* Decryption remains the same as in KEMDEM. It uses the decapsulated key.
     This is sound because IND-CPA security does not involve adversarial decryption queries.
     For PKE correctness, the original KEM key would be used. *)
  proc dec(sk: skey, c: kct * dct) : pt option = {
    var k_s_o: key option;
    var c_k: kct = c.`1;
    var c_d: dct = c.`2;
    var p_res: pt;
    k_s_o <@ KEM.dec(sk, c_k);
    if (k_s_o is None) { return None; }
    else {
      p_res <@ DEM.dec(oget k_s_o, c_d);
      return Some p_res;
    }
  }
}.

(* Simulator Sim_KEM: Constructs a KEM adversary from a PKE adversary APKE. *)
module Sim_KEM (APKE: PKE_Adv_CPA_Mod_Type, DEM: DEM_Mod_Type, _KD: KeyDistr)
               : KEM_Adv_CPA_Mod_Type = {
  var m0_sim_ : pt.    (* Stores m0 chosen by APKE *)
  var m1_sim_ : pt.    (* Stores m1 chosen by APKE *)
  var b_sim_  : bool.  (* Challenge bit chosen by Sim_KEM for APKE's sub-game *)

  proc distinguish(pk: pkey, k_chal: key, c_kem: kct) : bool = {
    var c_dem: dct;
    var b_pke_guess: bool; (* APKE's guess for b_sim_ *)
    var m_to_enc: pt;

    (m0_sim_, m1_sim_) <@ APKE.choose(pk); (* APKE chooses messages *)
    b_sim_ <$ {0,1}; (* Sim_KEM picks a challenge bit for APKE *)

    if (b_sim_) { m_to_enc = m1_sim_; } else { m_to_enc = m0_sim_; }

    c_dem <@ DEM.enc(k_chal, m_to_enc); (* Encrypt using the challenged KEM key k_chal *)
    b_pke_guess <@ APKE.distinguish((c_kem, c_dem)); (* APKE tries to guess b_sim_ *)

    (* Sim_KEM's goal is to guess b_exp (from KEM_CPA_Exp).
       b_exp=false means k_chal is real. b_exp=true means k_chal is random.
       If APKE wins (b_pke_guess = b_sim_), Sim_KEM guesses k_chal was real (output false).
       If APKE loses (b_pke_guess <> b_sim_), Sim_KEM guesses k_chal was random (output true).
       So, Sim_KEM returns true if APKE lost, false if APKE won.
       This is equivalent to: !(b_pke_guess = b_sim_)
    *)
    return !(b_pke_guess = b_sim_);
  }
}.

(* Simulator Sim_DEM: Constructs a DEM adversary from a PKE adversary APKE. *)
module Sim_DEM (APKE: PKE_Adv_CPA_Mod_Type, KEM: KEM_Mod_Type)
               : DEM_Adv_Pass_Mod_Type = {
  var pk_sim_    : pkey. (* Public key generated by KEM, for APKE.choose *)
  var c_kem_sim_ : kct.  (* KEM ciphertext, for APKE.distinguish *)
  (* sk_sim is not needed by the simulator's logic *)

  proc choose() : pt * pt = {
    var m0_apke : pt;
    var m1_apke : pt;
