    var sk_ignore : skey; (* Secret key, not used by Sim_DEM logic *)

    (pk_sim_, sk_ignore) <@ KEM.keygen();
    (k_s_ignore, c_kem_sim_) <@ KEM.enc(pk_sim_); (* c_kem_sim_ is stored for distinguish phase *)
