    return (m0_apke, m1_apke); (* These are passed to DEM_Pass_Exp *)
  }

  proc distinguish(c_dem_chal: dct) : bool = {
    var b_pke_guess: bool; (* APKE's guess for the challenge bit *)

    (* APKE receives (c_kem_sim_, c_dem_chal) as the PKE ciphertext *)
    b_pke_guess <@ APKE.distinguish((c_kem_sim_, c_dem_chal));
    (* Sim_DEM returns APKE's guess as its own guess for b_exp in DEM_Pass_Exp *)
    return b_pke_guess;
  }
